/**
 * 调试版创建 Bug - 步步截图 + 打印关键字段状态
 */
import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WS_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WS_DIR, 'tapd_cookies.json');
const SCREENSHOTS_DIR = path.join(WS_DIR, 'memory');

const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
const STEALTH = `
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh', 'en'] });
  window.chrome = { runtime: {} };
`;

async function snap(page, name) {
  const p = path.join(SCREENSHOTS_DIR, `tapd_debug_${name}.png`);
  await page.screenshot({ path: p, fullPage: false });
  console.log(`[screenshot] ${p}`);
}

const browser = await chromium.launch({
  headless: false,  // headed 模式，避免 WAF 和渲染问题
  args: ['--no-sandbox'],
});
const ctx = await browser.newContext({
  userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  viewport: { width: 1280, height: 900 },
});
await ctx.addInitScript(STEALTH);
await ctx.addCookies(cookies);
const page = await ctx.newPage();

console.log('Navigating to bug create page...');
await page.goto('https://www.tapd.cn/31253609/bugtrace/bugs/add', { waitUntil: 'networkidle', timeout: 30000 });

if (page.url().includes('login')) {
  console.error('TAPD session expired!');
  await browser.close();
  process.exit(1);
}
await snap(page, '01_loaded');

// 填标题
await page.fill('#BugTitle', '新手引导卡住');
console.log('Title filled');

// 优先级
await page.selectOption('#BugPriority', 'P2');
console.log('Priority set');

// 发现版本
try {
  await page.selectOption('#BugVersionReport', { label: '【1V1】正式版本V2.0' }, { timeout: 3000 });
  console.log('Version set (select)');
} catch {
  await page.fill('#BugVersionReport', '【1V1】正式版本V2.0');
  console.log('Version set (fill)');
}

// 模块
try {
  await page.selectOption('#BugModule', { label: '1V1' }, { timeout: 3000 });
  console.log('Module set (select)');
} catch {
  await page.fill('#BugModule', '1V1');
  console.log('Module set (fill)');
}

// 研发分支
try {
  await page.selectOption('#BugCustomFieldOne', { label: 'YZY_1V1 V1.0 Beta' }, { timeout: 3000 });
  console.log('Branch set (select)');
} catch (e) {
  console.warn('Branch select failed:', e.message);
}

// 处理人
console.log('Setting handler...');
const handlerInput = page.locator('#BugCurrentOwnerValue');
await handlerInput.click();
await page.waitForTimeout(500);
await handlerInput.fill('');
await handlerInput.type('叶枝君', { delay: 150 });
await page.waitForTimeout(2500);

// 检查下拉提示是否出现
const dropdown = page.locator('.select2-results, .autocomplete-suggestions, ul.ui-autocomplete, .suggest-list').first();
const hasDropdown = await dropdown.count() > 0;
console.log(`Autocomplete dropdown visible: ${hasDropdown}`);
if (hasDropdown) {
  const items = await dropdown.locator('li').allTextContents();
  console.log('Dropdown items:', items.slice(0, 5));
  await dropdown.locator('li').first().click();
  console.log('Clicked first autocomplete item');
} else {
  // 直接按 Enter
  await page.keyboard.press('Enter');
  console.log('Pressed Enter (no dropdown)');
}
await page.waitForTimeout(500);

// 检查处理人字段当前值
const handlerVal = await page.locator('#BugCurrentOwner').inputValue().catch(() => 'N/A');
const handlerDisplayVal = await page.locator('#BugCurrentOwnerValue').inputValue().catch(() => 'N/A');
console.log(`Handler hidden value: ${handlerVal}`);
console.log(`Handler display value: ${handlerDisplayVal}`);

await snap(page, '02_before_submit');

// 提交
console.log('Clicking submit...');
await page.locator('a#_view').click();
await page.waitForTimeout(5000);
await snap(page, '03_after_submit');

const finalUrl = page.url();
console.log('Final URL:', finalUrl);

// 检查是否有错误提示
const errMsg = await page.locator('.error-msg, .alert-danger, .error, [class*="error"]').allTextContents().catch(() => []);
if (errMsg.length > 0) {
  console.log('Error messages:', errMsg.slice(0, 5));
}

await browser.close();

