try {
  await page.selectOption('#BugCustomFieldOne', { label: 'YZY_1V1 V1.0 Beta' }, { timeout: 3000 });
  console.log('Branch set (select)');
} catch (e) {
  console.warn('Branch select failed:', e.message);
}

// 处理人 - 叶枝君 + 周以天
console.log('Setting handlers...');
const handlerInput = page.locator('#BugCurrentOwnerValue');
await handlerInput.click();
await page.waitForTimeout(500);
await handlerInput.fill('');

// 输入第一个处理人：叶枝君
await handlerInput.type('叶枝君', { delay: 150 });
await page.waitForTimeout(1500);

// 等下拉并点击
const dropdown1 = page.locator('.select2-results li, .autocomplete-suggestions li, ul.ui-autocomplete li, .suggest-list li').first();
const has1 = await dropdown1.count() > 0;
console.log(`Dropdown for 叶枝君 visible: ${has1}`);
if (has1) {
  const items1 = await page.locator('.select2-results li, .autocomplete-suggestions li, ul.ui-autocomplete li, .suggest-list li').allTextContents().catch(() => []);
  console.log('Dropdown items:', items1.slice(0, 5));
  await dropdown1.click();
  console.log('Clicked 叶枝君 in dropdown');
} else {
  await page.keyboard.press('Enter');
  console.log('Pressed Enter for 叶枝君');
}
await page.waitForTimeout(1000);

// 输入第二个处理人：周以天
await handlerInput.type('周以天', { delay: 150 });
await page.waitForTimeout(1500);

const dropdown2 = page.locator('.select2-results li, .autocomplete-suggestions li, ul.ui-autocomplete li, .suggest-list li').first();
const has2 = await dropdown2.count() > 0;
console.log(`Dropdown for 周以天 visible: ${has2}`);
if (has2) {
  const items2 = await page.locator('.select2-results li, .autocomplete-suggestions li, ul.ui-autocomplete li, .suggest-list li').allTextContents().catch(() => []);
  console.log('Dropdown items:', items2.slice(0, 5));
  await dropdown2.click();
  console.log('Clicked 周以天 in dropdown');
} else {
  await page.keyboard.press('Enter');
  console.log('Pressed Enter for 周以天');
}
await page.waitForTimeout(500);

// 抄送：周以天
console.log('Setting CC...');
const ccInput = page.locator('#BugCCValue, input[name="cc"], #BugCC_value').first();
if (await ccInput.count() > 0) {
  await ccInput.click();
  await page.waitForTimeout(300);
  await ccInput.type('周以天', { delay: 150 });
  await page.waitForTimeout(1500);

  const dropdownCC = page.locator('.select2-results li, .autocomplete-suggestions li, ul.ui-autocomplete li, .suggest-list li').first();
  const hasCC = await dropdownCC.count() > 0;
  if (hasCC) {
    await dropdownCC.click();
    console.log('CC 周以天 set via dropdown');
  } else {
    await page.keyboard.press('Enter');
    console.log('CC 周以天 set via Enter');
  }
  await page.waitForTimeout(500);
} else {
  console.warn('CC field not found, skipping');
}

await snap(page, '02_fields_filled');

// 附件上传
const attachmentExists = fs.existsSync(ATTACHMENT);
console.log(`Attachment exists: ${attachmentExists}`);
if (attachmentExists) {
  try {
    const fileInput = page.locator('#file_input');
    if (await fileInput.count() > 0) {
      await fileInput.setInputFiles(ATTACHMENT);
      console.log('Attachment uploaded');
      await page.waitForTimeout(2000);
    } else {
      console.warn('#file_input not found, skipping attachment');
    }
  } catch (e) {
    console.warn('Attachment upload failed:', e.message);
  }
}

await snap(page, '03_before_submit');

// 提交
console.log('Clicking submit...');
await page.locator('a#_view').click();
await page.waitForTimeout(5000);
await snap(page, '04_after_submit');

const finalUrl = page.url();
console.log('Final URL:', finalUrl);

// 检查是否有错误提示
const errMsg = await page.locator('.error-msg, .alert-danger, .error, [class*="error"]').allTextContents().catch(() => []);
if (errMsg.length > 0) {
  console.log('Error messages:', errMsg.filter(m => m.trim()).slice(0, 5));
}

await browser.close();
console.log('Done.');

